class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        unordered_set<string> startSet;
        for (const auto& word : startWords) {
            string sortedWord = word;
            sort(sortedWord.begin(), sortedWord.end());
            startSet.insert(sortedWord);
        }
        int count = 0;
        for (const auto& word : targetWords) {
            string sortedWord = word;
            sort(sortedWord.begin(), sortedWord.end());
            if (startSet.find(sortedWord) != startSet.end()) {
                count++;
            } else {
                for (int i = 0; i < 26; i++) {
                    char c = 'a' + i;
                    string newWord = sortedWord + c;
                    sort(newWord.begin(), newWord.end());
                    if (startSet.find(newWord) != startSet.end()) {
                        count++;
                        break;
                    }
                }
            }
        }
        return count;
    }
};
